const plain = $node["Prep JD"].json.clean_job_description_plain || '';
// Extract job title from raw job_description (preserves newlines from webhook input)
// Prep JD collapses everything to one line, so we must use the raw field
const raw = ($json.job_description || $json.clean_job_description || '').toString();
const skipPattern = /[£$€]|^\d|hybrid|remote|office|salary|bonus|pension|holiday|days|working/i;
const firstLine = raw.split(/\n/).map(l => l.trim()).filter(l => l.length > 2 && !skipPattern.test(l))[0] || '';
return [{
  ...$json,
  clean_job_description_plain: plain,
  clean_job_description: $node["Prep JD"].json.clean_job_description,
  jd_first_line: firstLine
}];

const content = ($json.text || $json.output || $json.response || $json.message || $json.data?.text || "{}").toString();

function cleanAndParse(str) {
  if (!str || str.trim() === "{}") return {};

  // 1. Basic JSON parse
  try { return JSON.parse(str); } catch (e) {}

  // 2. Try to find the JSON block via first { and last }
  const start = str.indexOf('{');
  const end = str.lastIndexOf('}');
  if (start === -1 || end === -1 || end < start) return {};
  let jsonStr = str.substring(start, end + 1);

  // 3. Clean common LLM mistakes
  try { return JSON.parse(jsonStr); } catch (e) {
    jsonStr = jsonStr
      .replace(/\/\/.*$/gm, '') // Remove single line comments
      .replace(/\/\*[\s\S]*?\*\//g, '') // Remove multi line comments
      .replace(/,\s*([}\]])/g, '$1') // Remove trailing commas
      .replace(/[\x00-\x1F\x7F-\x9F]/g, ""); // Remove control characters and non-printable

    try { return JSON.parse(jsonStr); } catch (e2) {
      // Last resort: try to fix unescaped newlines in strings
      try {
         const fixed = jsonStr.replace(/:\s*"([\s\S]*?)"/g, (m, p1) => {
           return ': "' + p1.replace(/\n/g, '\\n').replace(/\r/g, '\\r') + '"';
         });
         return JSON.parse(fixed);
      } catch (e3) {
         return {}; // Give up
      }
    }
  }
}

const parsed = cleanAndParse(content);
return [{ json: { ...$json, analysis: parsed } }];

function pad(n){return n.toString().padStart(2,'0');}
const now = new Date();
const ts = `${now.getFullYear()}${pad(now.getMonth()+1)}${pad(now.getDate())}_${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;

// Redundant access to analysis data for maximum compatibility
let analysis = {};
try { analysis = $('Parse Analysis').first().json.analysis || {}; } catch (e) {
  try { analysis = $node["Parse Analysis"].json.analysis || {}; } catch (e2) { analysis = {}; }
}

// Use LLM-extracted title, but fall back to the first line of the JD extracted in Attach JD (reliable)
const jdFirstLine = $json.jd_first_line || '';
const title = (analysis.job_title && analysis.job_title.trim() ? analysis.job_title : jdFirstLine || 'job').toString();
const company = (analysis.company && analysis.company.trim() ? analysis.company : '').toString();
const safe = s => s.replace(/[^a-zA-Z0-9]+/g,'_').replace(/^_+|_+$/g,'').toLowerCase();
const base = `${ts}__${safe(title)}__${safe(company)}`;
const webhookBase = ($env.WEBHOOK_URL || '').replace(/\/+$/,'') + '/';
const token = $env.CV_DOWNLOAD_TOKEN || '';
// Get output from each stage, with fallbacks
const cvEnhanced = ($node["CV Enhance (DBA)"].json.text || $node["CV Enhance (DBA)"].json.output || $node["CV Enhance (DBA)"].json.response || $node["CV Enhance (DBA)"].json.message || '').trim();
const cvReviewed = ($node["Review CV"].json.text || $node["Review CV"].json.output || $node["Review CV"].json.response || $node["Review CV"].json.message || '').trim();
const cvGenerated = ($node["Generate CV"].json.text || $node["Generate CV"].json.output || $node["Generate CV"].json.response || $node["Generate CV"].json.message || '').trim();

// Detect truncation: a complete CV must contain Availability and Certifications sections
const isComplete = s => s.includes('Availability') && s.includes('Certif');

// Use the most-processed complete version, falling back to earlier stages if truncated
const finalCv = isComplete(cvEnhanced) ? cvEnhanced : isComplete(cvReviewed) ? cvReviewed : cvGenerated;

const cover = $node["Generate Cover Letter"].json.text || $node["Generate Cover Letter"].json.output || $node["Generate Cover Letter"].json.response || $node["Generate Cover Letter"].json.message || '';
return [{
  ...$json,
  ts,
  cv_filename: `${base}.docx`,
  cover_filename: `${base}_cover.docx`,
  cv_markdown: finalCv,
  cover_markdown: cover,
  cv_download_url: `${webhookBase}webhook/cv-download?file=${encodeURIComponent(`${base}.docx`)}&token=${token}`,
  cover_download_url: `${webhookBase}webhook/cv-download?file=${encodeURIComponent(`${base}_cover.docx`)}&token=${token}`
}];

const fs = require('fs');
const path = '/cvdata/generated_cv/' + $json.cv_filename.replace('.docx', '.md');
fs.mkdirSync('/cvdata/generated_cv', { recursive: true });
fs.writeFileSync(path, $json.cv_markdown, 'utf8');
return [$input.item];

const fs = require('fs');
const path = '/cvdata/generated_cv/' + $json.cover_filename.replace('.docx', '.md');
fs.mkdirSync('/cvdata/generated_cv', { recursive: true });
fs.writeFileSync(path, $json.cover_markdown, 'utf8');
return [$input.item];

const html = $json.body || $json.data || $json || '';
const text = typeof html === 'string' ? html : '';
let posting = null;

// 1) Try JSON-LD JobPosting
const regex = /<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
let match;
while ((match = regex.exec(text)) !== null) {
  const raw = match[1].trim();
  try {
    const obj = JSON.parse(raw);
    if (obj['@type'] === 'JobPosting') { posting = obj; break; }
  } catch (e) {}
}

// 2) Fallback: parse Next.js data
let description = posting?.description || '';
if (!description) {
  const nextMatch = text.match(/<script[^>]*id=["']__NEXT_DATA__["'][^>]*>([\s\S]*?)<\/script>/i);
  if (nextMatch) {
    try {
      const nextData = JSON.parse(nextMatch[1]);
      description = nextData?.props?.pageProps?.consolidatedJobDetails?.jobDetails?.description || '';
    } catch (e) {}
  }
}

return [{ clean_job_description: description }];
